import { z } from "zod";

export const moderateTextRequestSchema = z.object({
  text: z.string().min(1).max(10000),
});

export const moderateImageRequestSchema = z.object({
  image: z.string().min(1),
  format: z.enum(["png", "jpeg", "webp"]).optional().default("jpeg"),
});

export const moderationCategorySchema = z.object({
  label: z.string(),
  confidence: z.number().min(0).max(1),
  flagged: z.boolean(),
});

export const moderateResponseSchema = z.object({
  safe: z.boolean(),
  categories: z.array(moderationCategorySchema),
  overallScore: z.number().min(0).max(1),
});

export type ModerateTextRequest = z.infer<typeof moderateTextRequestSchema>;
export type ModerateImageRequest = z.infer<typeof moderateImageRequestSchema>;
export type ModerateResponse = z.infer<typeof moderateResponseSchema>;
